export const CONTENT_HTML = "<p class=\"intro\">Trước khi học hình họa, trang trí màu hay bố cục màu — người học mỹ thuật cần hiểu một thứ gọi là <strong>ngôn ngữ thị giác</strong>. Cơ sở tạo hình chính là môn học dạy ngôn ngữ ấy, nền tảng lý thuyết và thực hành mà mọi ngành sáng tạo đều dựa vào.</p>\r\n\r\n<div class=\"stats break-half\">\r\n  <div class=\"stat\"><div class=\"stat-num\">7+7</div><div class=\"stat-label\">Yếu tố &amp; Nguyên lý</div><div class=\"stat-sub\">Bộ ngữ pháp thị giác</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">3</div><div class=\"stat-label\">Môn thực hành</div><div class=\"stat-sub\">Hình họa · Bố cục · Trang trí</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">12–24</div><div class=\"stat-label\">Tháng luyện thi</div><div class=\"stat-sub\">Kỳ thi khối H, V</div></div>\r\n</div>\r\n\r\n<!-- 01 · ĐỊNH NGHĨA -->\r\n<div class=\"div-sec\" id=\"sec-1\">\r\n  <div class=\"div-num\"><em>01</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Định nghĩa</p>\r\n    <h2 class=\"div-title\">Cơ sở tạo hình là gì?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p><strong>Cơ sở tạo hình</strong> <em>(Basic Visual Design)</em> là môn học nghiên cứu có hệ thống các yếu tố thị giác cơ bản và các nguyên lý tổ chức chúng thành một tổng thể có giá trị thẩm mỹ.</p>\r\n\r\n<p>Nếu coi một tác phẩm là một câu nói, cơ sở tạo hình chính là <strong>bảng chữ cái và ngữ pháp</strong> của ngôn ngữ thị giác. Bạn có thể \"nói bừa\" mà không cần ngữ pháp — nhưng nếu muốn diễn đạt có chiều sâu, đúng và đẹp, ngữ pháp là thứ không thể bỏ qua.</p>\r\n\r\n<!-- GALLERY-3 · 3 tác phẩm đại diện 3 nền văn hoá -->\r\n<div class=\"gallery gallery-3\">\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/co-so-tao-hinh/gallery-01-mona-lisa.png\" alt=\"Leonardo da Vinci — Mona Lisa: phân tích bố cục tam giác\" loading=\"lazy\" decoding=\"async\" />\r\n    <figcaption class=\"gallery-cap\"><span class=\"gallery-num\">01</span> Mona Lisa — Leonardo da Vinci</figcaption>\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/co-so-tao-hinh/gallery-02-mondrian.png\" alt=\"Piet Mondrian — bố cục hình học với màu nguyên\" loading=\"lazy\" decoding=\"async\" />\r\n    <figcaption class=\"gallery-cap\"><span class=\"gallery-num\">02</span> Composition — Piet Mondrian</figcaption>\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/co-so-tao-hinh/gallery-03-hokusai.jpg\" alt=\"Hokusai — Sóng lừng Kanagawa, tranh khắc gỗ Nhật\" loading=\"lazy\" decoding=\"async\" />\r\n    <figcaption class=\"gallery-cap\"><span class=\"gallery-num\">03</span> The Great Wave — Hokusai</figcaption>\r\n  </figure>\r\n</div>\r\n\r\n<p>Ba tác phẩm trên — cách nhau hàng thế kỷ, thuộc những nền văn hoá khác biệt — đều tuân theo cùng <em>một bộ nguyên tắc cơ sở tạo hình</em>. Đây là lý do môn này được coi là nền tảng phổ quát.</p>\r\n\r\n<div class=\"gls\">\r\n  <p class=\"gls-head\">A — Thuật ngữ cơ bản</p>\r\n  <div class=\"gls-body\">\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Thị giác<small>Visual perception</small></p><p class=\"gls-def\">Cách mắt và não bộ xử lý hình ảnh ta nhìn thấy.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Bố cục<small>Composition</small></p><p class=\"gls-def\">Cách sắp xếp các yếu tố trong một khuôn khổ.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Hòa sắc<small>Color harmony</small></p><p class=\"gls-def\">Sự phối hợp màu tạo cảm giác dễ chịu cho mắt.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Tả khối<small>Rendering form</small></p><p class=\"gls-def\">Diễn tả chiều sâu 3D qua sáng tối và chất liệu.</p></div>\r\n  </div>\r\n</div>\r\n\r\n<!-- BLEED-DUAL · Hai bối cảnh học: chính quy vs đời thường -->\r\n<div class=\"bleed-dual\">\r\n  <div class=\"bleed-box variant-a\">\r\n    <span class=\"bleed-vs\">A</span>\r\n    <img src=\"/img/co-so-tao-hinh/bleed-a-truong-dh.jpg\" alt=\"Cơ sở tạo hình trong môi trường đào tạo mỹ thuật\" loading=\"lazy\" />\r\n    <p class=\"bleed-note\">Cơ sở tạo hình trong môi trường đào tạo mỹ thuật</p>\r\n  </div>\r\n  <div class=\"bleed-box variant-b\">\r\n    <span class=\"bleed-vs\">B</span>\r\n    <img src=\"/img/co-so-tao-hinh/bleed-b-kid.jpg\" alt=\"Cơ sở tạo hình trong thực tế, tự nhiên\" loading=\"lazy\" />\r\n    <p class=\"bleed-note\">Cơ sở tạo hình trong thực tế, tự nhiên</p>\r\n  </div>\r\n</div>\r\n\r\n<!-- 02 · LÝ DO -->\r\n<div class=\"div-sec\" id=\"sec-2\">\r\n  <div class=\"div-num\"><em>02</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Lý do</p>\r\n    <h2 class=\"div-title\">Tại sao phải học?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Nhiều bạn mới muốn nhảy thẳng vào vẽ chân dung hay phong cảnh. Điều đó cũng giống như muốn viết tiểu thuyết khi chưa thuộc mặt chữ — làm được, nhưng giới hạn rất nhanh.</p>\r\n\r\n<div class=\"cmp break-half\">\r\n  <div class=\"cmp-col l\">\r\n    <p class=\"cmp-lbl\">Không có nền tảng</p>\r\n    <p class=\"cmp-title\">Vẽ theo cảm tính</p>\r\n    <ul class=\"cmp-list\">\r\n      <li>Thấy đẹp thì vẽ theo, không giải thích được tại sao</li>\r\n      <li>Gặp chủ đề mới thì bí, phải tìm tham khảo liên tục</li>\r\n      <li>Không biết bài mình sai ở đâu để sửa</li>\r\n      <li>Khó chuyển ngành (vẽ → thiết kế → animation)</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"cmp-col r\">\r\n    <p class=\"cmp-lbl\">Có nền tảng</p>\r\n    <p class=\"cmp-title\">Vẽ có chủ đích</p>\r\n    <ul class=\"cmp-list\">\r\n      <li>Hiểu tại sao bài mình đẹp hoặc chưa đẹp</li>\r\n      <li>Sáng tác được từ ý tưởng gốc, không cần tham khảo</li>\r\n      <li>Tự chẩn đoán lỗi — bố cục, sắc độ hay tỉ lệ</li>\r\n      <li>Dễ chuyển ngành vì nguyên lý chung</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n<!-- SPREAD · Học vẽ vs học nhìn -->\r\n<div class=\"spread break-half\">\r\n  <div class=\"spread-text\">\r\n    <p class=\"spread-kicker\">Góc nhìn</p>\r\n    <h3 class=\"spread-title\">Học vẽ khác học nhìn</h3>\r\n    <p>Học vẽ dạy bạn điều khiển cây chì. Học cơ sở tạo hình dạy bạn điều khiển <strong>đôi mắt</strong>.</p>\r\n    <p>Người có kỹ thuật tốt mà không có nền tảng thường vẽ giỏi ở 1 phong cách, rồi khựng lại. Người có nền tảng vững dù kỹ thuật chưa điêu luyện vẫn tiến bộ đều — vì họ biết mình đang đi về đâu.</p>\r\n    <p>Đây là khác biệt giữa <em>thợ vẽ</em> và <em>họa sĩ.</em></p>\r\n  </div>\r\n  <div class=\"spread-img\" data-img=\"IMG_09\">\r\n    <img src=\"/img/co-so-tao-hinh/spread-artist.jpg\" alt=\"Nghệ sĩ quan sát và ký họa từ mẫu thật\" loading=\"lazy\" decoding=\"async\" />\r\n  </div>\r\n</div>\r\n\r\n<div class=\"pq\">\r\n  <p class=\"pq-text\">Học cơ sở tạo hình là học cách nhìn thế giới bằng đôi mắt của <em>một người sáng tạo.</em></p>\r\n  <span class=\"pq-cite\">— Triết lý giảng dạy tại Sine Art</span>\r\n</div>\r\n\r\n<!-- 03 · 7 YẾU TỐ với HOVER REVEAL -->\r\n<div class=\"div-sec\" id=\"sec-3\">\r\n  <div class=\"div-num\"><em>03</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Yếu tố</p>\r\n    <h2 class=\"div-title\">7 yếu tố tạo hình</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Bảy \"chữ cái\" của ngôn ngữ thị giác. Hover vào từng yếu tố bên dưới để xem minh hoạ tương ứng.</p>\r\n\r\n<!-- EL-LIST-HOVER · 7 yếu tố -->\r\n<div class=\"el-list-hover\">\r\n  <div class=\"el-list-hover-items\">\r\n    <div class=\"el-hover-item\" data-target=\"el01\" onmouseover=\"showPanel('el01')\">\r\n      <span class=\"el-hover-n\">01</span>\r\n      <div><p class=\"el-hover-name\">Điểm <em>Point</em></p><p class=\"el-hover-desc\">Đơn vị nhỏ nhất của thị giác. Đánh dấu vị trí, tạo trọng tâm, gợi sự tập trung.</p></div>\r\n    </div>\r\n    <div class=\"el-hover-item\" data-target=\"el02\" onmouseover=\"showPanel('el02')\">\r\n      <span class=\"el-hover-n\">02</span>\r\n      <div><p class=\"el-hover-name\">Đường <em>Line</em></p><p class=\"el-hover-desc\">Đường thẳng gợi ổn định, đường cong gợi chuyển động, đường gấp gợi căng thẳng.</p></div>\r\n    </div>\r\n    <div class=\"el-hover-item\" data-target=\"el03\" onmouseover=\"showPanel('el03')\">\r\n      <span class=\"el-hover-n\">03</span>\r\n      <div><p class=\"el-hover-name\">Hình <em>Shape</em></p><p class=\"el-hover-desc\">Diện tích 2D giới hạn bởi đường. Hình học gợi trật tự, hình hữu cơ gợi tự nhiên.</p></div>\r\n    </div>\r\n    <div class=\"el-hover-item\" data-target=\"el04\" onmouseover=\"showPanel('el04')\">\r\n      <span class=\"el-hover-n\">04</span>\r\n      <div><p class=\"el-hover-name\">Khối <em>Form</em></p><p class=\"el-hover-desc\">Phiên bản 3D của hình. Là cơ sở của môn tả khối trong hình họa.</p></div>\r\n    </div>\r\n    <div class=\"el-hover-item\" data-target=\"el05\" onmouseover=\"showPanel('el05')\">\r\n      <span class=\"el-hover-n\">05</span>\r\n      <div><p class=\"el-hover-name\">Không gian <em>Space</em></p><p class=\"el-hover-desc\">Không gian dương chứa hình, không gian âm tạo chỗ thở cho bố cục.</p></div>\r\n    </div>\r\n    <div class=\"el-hover-item\" data-target=\"el06\" onmouseover=\"showPanel('el06')\">\r\n      <span class=\"el-hover-n\">06</span>\r\n      <div><p class=\"el-hover-name\">Màu sắc <em>Color</em></p><p class=\"el-hover-desc\">Yếu tố có tác động cảm xúc mạnh nhất. Quyết định tâm trạng tác phẩm.</p></div>\r\n    </div>\r\n    <div class=\"el-hover-item\" data-target=\"el07\" onmouseover=\"showPanel('el07')\">\r\n      <span class=\"el-hover-n\">07</span>\r\n      <div><p class=\"el-hover-name\">Chất cảm <em>Texture</em></p><p class=\"el-hover-desc\">Bề mặt của vật thể — thô, mịn, bóng, xù xì. Tạo sự đa dạng xúc giác.</p></div>\r\n    </div>\r\n  </div>\r\n  <div class=\"el-hover-panel\" id=\"hoverPanel-el\">\r\n    <div class=\"panel-slide active\" data-slide=\"el01\">\r\n      <img src=\"/img/img10-dot.jpg\" alt=\"Điểm — Point\" loading=\"lazy\" />\r\n      <p class=\"panel-note\">Điểm đơn lẻ trên khung trống — công cụ tạo tâm điểm mạnh nhất</p>\r\n    </div>\r\n    <div class=\"panel-slide\" data-slide=\"el02\">\r\n      <img src=\"/img/img11-line.jpg\" alt=\"Đường — Line\" loading=\"lazy\" />\r\n      <p class=\"panel-note\">Đường thẳng, cong, gấp — mỗi loại mang thông điệp khác</p>\r\n    </div>\r\n    <div class=\"panel-slide\" data-slide=\"el03\">\r\n      <img src=\"/img/img12-shape.jpg\" alt=\"Hình — Shape\" loading=\"lazy\" />\r\n      <p class=\"panel-note\">Hình học vs hình hữu cơ từ tự nhiên</p>\r\n    </div>\r\n    <div class=\"panel-slide\" data-slide=\"el04\">\r\n      <img src=\"/img/img13-form.jpg\" alt=\"Khối — Form\" loading=\"lazy\" />\r\n      <p class=\"panel-note\">Khối 3D — nền tảng của tả khối trong hình họa</p>\r\n    </div>\r\n    <div class=\"panel-slide\" data-slide=\"el05\">\r\n      <img src=\"/img/img14-negative.jpg\" alt=\"Không gian — Space\" loading=\"lazy\" />\r\n      <p class=\"panel-note\">Không gian dương và âm cân bằng nhau</p>\r\n    </div>\r\n    <div class=\"panel-slide\" data-slide=\"el06\">\r\n      <img src=\"/img/img15-color.jpg\" alt=\"Màu sắc — Color\" loading=\"lazy\" />\r\n      <p class=\"panel-note\">Màu sắc — yếu tố tác động cảm xúc mạnh nhất</p>\r\n    </div>\r\n    <div class=\"panel-slide\" data-slide=\"el07\">\r\n      <img src=\"/img/img16-texture.jpg\" alt=\"Chất cảm — Texture\" loading=\"lazy\" />\r\n      <p class=\"panel-note\">Chất cảm bề mặt — tạo cảm giác xúc giác qua thị giác</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<!-- 04 · 7 NGUYÊN LÝ -->\r\n<div class=\"div-sec\" id=\"sec-4\">\r\n  <div class=\"div-num\"><em>04</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Nguyên lý</p>\r\n    <h2 class=\"div-title\">7 nguyên lý tổ chức</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Nếu 7 yếu tố là \"chữ cái\", thì 7 nguyên lý là \"quy tắc ghép chữ thành câu\". Chúng quyết định một tổ hợp yếu tố có trở thành tác phẩm hay chỉ là mớ hỗn độn.</p>\r\n\r\n<div class=\"pr-table\">\r\n  <div class=\"pr-row\"><span class=\"pr-i\">i.</span><div class=\"pr-n\">Cân bằng<small>Balance</small></div><div class=\"pr-d\">Phân bố sức nặng thị giác. Đối xứng ổn định, bất đối xứng tạo năng lượng.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">ii.</span><div class=\"pr-n\">Nhịp điệu<small>Rhythm</small></div><div class=\"pr-d\">Lặp lại có chủ đích. Tạo chuyển động dẫn mắt qua bố cục.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">iii.</span><div class=\"pr-n\">Tương phản<small>Contrast</small></div><div class=\"pr-d\">Sự khác biệt giữa các yếu tố. Tương phản càng mạnh, tác phẩm càng \"hét\".</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">iv.</span><div class=\"pr-n\">Nhấn mạnh<small>Emphasis</small></div><div class=\"pr-d\">Tạo điểm thu hút chính — nơi mắt dừng lại đầu tiên.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">v.</span><div class=\"pr-n\">Tỉ lệ<small>Proportion</small></div><div class=\"pr-d\">Quan hệ kích thước. Tỉ lệ vàng, quy luật 1/3.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">vi.</span><div class=\"pr-n\">Hài hòa<small>Harmony</small></div><div class=\"pr-d\">Sự ăn khớp giữa các yếu tố. Tạo cảm giác hoàn chỉnh.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">vii.</span><div class=\"pr-n\">Thống nhất<small>Unity</small></div><div class=\"pr-d\">Nguyên lý bao trùm — mọi thành phần phục vụ một ý tưởng.</div></div>\r\n</div>\r\n\r\n<!-- GALLERY-4 · Minh hoạ 4 nguyên lý chính -->\r\n<div class=\"gallery gallery-4\">\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/co-so-tao-hinh/principle-01-balance.png\" alt=\"Cân bằng — Balance: bố cục đối xứng cổ điển\" loading=\"lazy\" decoding=\"async\" />\r\n    <figcaption class=\"gallery-cap\"><span class=\"gallery-num\">i</span> Cân bằng — Balance</figcaption>\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/co-so-tao-hinh/principle-02-rhythm.png\" alt=\"Nhịp điệu — Rhythm: lặp lại có chủ đích\" loading=\"lazy\" decoding=\"async\" />\r\n    <figcaption class=\"gallery-cap\"><span class=\"gallery-num\">ii</span> Nhịp điệu — Rhythm</figcaption>\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/co-so-tao-hinh/principle-03-contrast.jpg\" alt=\"Tương phản — Contrast: chiaroscuro mạnh\" loading=\"lazy\" decoding=\"async\" />\r\n    <figcaption class=\"gallery-cap\"><span class=\"gallery-num\">iii</span> Tương phản — Contrast</figcaption>\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/co-so-tao-hinh/principle-04-emphasis.png\" alt=\"Nhấn mạnh — Emphasis: điểm thu hút thị giác\" loading=\"lazy\" decoding=\"async\" />\r\n    <figcaption class=\"gallery-cap\"><span class=\"gallery-num\">iv</span> Nhấn mạnh — Emphasis</figcaption>\r\n  </figure>\r\n</div>\r\n\r\n<div class=\"tips\">\r\n  <div class=\"tip\"><span class=\"tip-n\">01</span><div class=\"tip-c\"><p class=\"tip-t\">Quan sát trước, vẽ sau</p><p class=\"tip-d\">30% thời gian nhìn mẫu, 70% thời gian vẽ. Đa số người mới đảo ngược tỷ lệ này.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">02</span><div class=\"tip-c\"><p class=\"tip-t\">Sai lớn trước, sai nhỏ sau</p><p class=\"tip-d\">Vẽ tỉ lệ tổng thể trước, chi tiết sau.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">03</span><div class=\"tip-c\"><p class=\"tip-t\">Vẽ nhanh, vẽ nhiều</p><p class=\"tip-d\">10 bức 30 phút giá trị hơn 1 bức 5 tiếng.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">04</span><div class=\"tip-c\"><p class=\"tip-t\">Học người khác, không copy</p><p class=\"tip-d\">Phân tích tại sao họa sĩ chọn vậy, đừng chép y nguyên.</p></div></div>\r\n</div>\r\n\r\n<!-- 05 · ỨNG DỤNG -->\r\n<div class=\"div-sec\" id=\"sec-5\">\r\n  <div class=\"div-num\"><em>05</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Ứng dụng</p>\r\n    <h2 class=\"div-title\">Ba môn thực hành</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Lý thuyết cơ sở tạo hình không đứng một mình. Nó là đầu vào trực tiếp cho 3 môn thực hành trọng yếu:</p>\r\n\r\n<div class=\"subj-row break-half\">\r\n  <div class=\"subj hh\" data-img=\"IMG_17\" style=\"background-image:url(/img/co-so-tao-hinh/subj-01-hh.jpg);background-size:cover;background-position:center\">\r\n    <span class=\"subj-tag\">Khối V</span>\r\n    <h4>Hình họa</h4>\r\n  </div>\r\n  <div class=\"subj tt\" data-img=\"IMG_18\" style=\"background-image:url(/img/co-so-tao-hinh/subj-02-bc.png);background-size:cover;background-position:center\">\r\n    <span class=\"subj-tag\">Khối H</span>\r\n    <h4>Bố cục màu</h4>\r\n  </div>\r\n  <div class=\"subj tt\" data-img=\"IMG_19\" style=\"background-image:url(/img/co-so-tao-hinh/subj-03-tt.jpg);background-size:cover;background-position:center\">\r\n    <span class=\"subj-tag\">Nền tảng</span>\r\n    <h4>Trang trí màu</h4>\r\n  </div>\r\n</div>\r\n\r\n<!-- 06 · LỘ TRÌNH -->\r\n<div class=\"div-sec\" id=\"sec-6\">\r\n  <div class=\"div-num\"><em>06</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Lộ trình</p>\r\n    <h2 class=\"div-title\">12–24 tháng luyện thi</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Với học sinh chuẩn bị thi khối H, V, lộ trình hợp lý kéo dài <strong>12–24 tháng</strong>:</p>\r\n\r\n<div class=\"tl\">\r\n  <div class=\"tl-item s1\">\r\n    <p class=\"tl-label\">Giai đoạn 1 · 3 tháng</p>\r\n    <h4 class=\"tl-title\">Nhập môn</h4>\r\n    <p class=\"tl-desc\">Làm quen yếu tố cơ bản qua bài tập đường nét, hình khối đơn giản. Rèn thói quen quan sát tỉ lệ, nhìn sáng tối.</p>\r\n  </div>\r\n  <div class=\"tl-item s2\">\r\n    <p class=\"tl-label\">Giai đoạn 2 · 6–12 tháng</p>\r\n    <h4 class=\"tl-title\">Chuyên sâu</h4>\r\n    <p class=\"tl-desc\">Tách nhánh theo mục tiêu. Khối V tập trung tĩnh vật, tượng, người mẫu. Khối H tập trung trang trí màu và sáng tác bố cục.</p>\r\n  </div>\r\n  <div class=\"tl-item s3\">\r\n    <p class=\"tl-label\">Giai đoạn 3 · 3–6 tháng</p>\r\n    <h4 class=\"tl-title\">Luyện thi</h4>\r\n    <p class=\"tl-desc\">Làm đề cấu trúc thi thật, luyện tốc độ, chấm chéo, phản biện giảng viên.</p>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"dd break-half\">\r\n  <div class=\"dd-col good\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">+</span><span class=\"dd-title\">Nên làm</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Vẽ mỗi ngày tối thiểu 30 phút</li>\r\n      <li>Lưu lại bài cũ để so sánh tiến bộ</li>\r\n      <li>Nhờ người có chuyên môn chấm sửa</li>\r\n      <li>Đọc sách nền tảng song song với vẽ</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"dd-col bad\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">−</span><span class=\"dd-title\">Nên tránh</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Bỏ qua bài cơ bản vì \"thấy dễ\"</li>\r\n      <li>So sánh bài mình với người học 5 năm</li>\r\n      <li>Dùng ảnh tham khảo thay quan sát trực tiếp</li>\r\n      <li>Tập trung quá vào 1 kỹ năng, bỏ mặt khác</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"key break\">\r\n  <p class=\"key-lbl\">⭐ Điểm mấu chốt</p>\r\n  <p class=\"key-t\">Cơ sở tạo hình không phải môn \"vẽ\" — nó là môn <em>tư duy thị giác.</em></p>\r\n  <p class=\"key-d\">Bạn học để nhìn, để phân tích, để giải thích được mọi hình ảnh xung quanh. Kỹ thuật vẽ chỉ là công cụ thể hiện tư duy đó ra giấy.</p>\r\n</div>\r\n\r\n<!-- 07 · FAQ -->\r\n<div class=\"div-sec\" id=\"sec-7\">\r\n  <div class=\"div-num\"><em>07</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">FAQ</p>\r\n    <h2 class=\"div-title\">Câu hỏi thường gặp</h2>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"faq\">\r\n  <details open>\r\n    <summary>Người chưa từng vẽ có học được không?<span class=\"faq-icon\">−</span></summary>\r\n    <p>Hoàn toàn được. Cơ sở tạo hình được thiết kế cho người bắt đầu từ con số không. Điều kiện duy nhất là sự kiên trì và thái độ quan sát cẩn thận.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Mất bao lâu để thi khối H, V?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Thông thường 12–24 tháng cho người bắt đầu từ con số không. Học sinh có nền tảng phổ thông tốt có thể rút ngắn còn 6–12 tháng.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Có thể tự học tại nhà không?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Lý thuyết có thể tự học qua video. Nhưng thực hành cần người chấm sửa — mắt người mới chưa đủ nhạy để tự phát hiện lỗi sai.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Khác gì với học vẽ thông thường?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Học vẽ dạy kỹ thuật thao tác cây chì. Cơ sở tạo hình dạy tư duy thị giác — tại sao một bố cục đẹp, tại sao một màu hợp màu khác.</p>\r\n  </details>\r\n</div>";

